7	      expect(quote({ items: [], yearsWithMHPCO: 0, previousQuotes: 0 })).toBe(5);
8	    });
9	    it("should compute premium for a single sword (base 100 G) for a first-time non-loyal customer", () => {
10	      expect(
11	        quote({
12	          items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
13	          yearsWithMHPCO: 0,
14	          previousQuotes: 0,
15	        }),
16	      ).toBe(115);
17	    });
18	    it.todo("should compute premium for a single amulet (base 60 G) for a first-time non-loyal customer");
19	    it.todo("should compute premium for a single staff (base 80 G) for a first-time non-loyal customer");
20	    it.todo("should compute premium for a single potion (base 40 G) for a first-time non-loyal customer");
21	  });
22	
23	  describe("quote - single component base premium", () => {
24	    it.todo("should compute premium for a single rune (base 25 G) for a first-time non-loyal customer");
25	    it.todo("should compute premium for a single moonstone (base 25 G) for a first-time non-loyal customer");
26	  });
27	
28	  describe("quote - multiple items sum base premiums", () => {
29	    it.todo("should sum base premiums for two different main items");
30	    it.todo("should sum base premiums for a main item and a component");
31	  });
32	
33	  describe("quote - component bundling (3 alike = 60 G)", () => {
34	    it.todo("should price a bundle of 3 alike runes at 60 G instead of 75 G");
