55	
56	  describe("quote - processing fee and rounding", () => {
57	    it.todo("should add a flat 5 G processing fee to every premium");
58	    it.todo("should round the premium up to the nearest whole G (MHPCO's favor)");
59	  });
60	
61	  describe("claim - basic payout rules", () => {
62	    it.todo("should subtract the 100 G deductible from a standard damage amount");
63	    it.todo("should pay out 0 when the damage amount is at or below the 100 G deductible");
64	    it.todo("should reimburse 50% of the damage for items with enchantment >= 8 (after deductible)");
